use std::collections::HashMap;
fn two_sum(nums: Vec<i32>, target: i32) -> Option<Vec<usize>> {
  let mut map = HashMap::new();
  for (i, num) in nums.iter().enumerate() {
    if let Some(&j) = map.get(&(target - num)) {
      return Some(vec![j, i]);
    }
    map.insert(num, i);
  }
  None
}
